// ---------------------------------------------------------------------------
// Per-ring bounding boxes — broad-phase to skip rings that can't contain a
// point. With 723 rings this makes isLand() ~8x faster vs naïve scan.
// ---------------------------------------------------------------------------
const RING_BBOX = new Float32Array(LAND_POLYGONS.length * 4);
(function buildBBoxes() {
  for (let p = 0; p < LAND_POLYGONS.length; p++) {
    const ring = LAND_POLYGONS[p];
    let minX = Infinity, minY = Infinity, maxX = -Infinity, maxY = -Infinity;
    for (let i = 0; i < ring.length; i += 2) {
      const x = ring[i], y = ring[i + 1];
      if (x < minX) minX = x;
      if (x > maxX) maxX = x;
      if (y < minY) minY = y;
      if (y > maxY) maxY = y;
    }
    RING_BBOX[p * 4]     = minX;
    RING_BBOX[p * 4 + 1] = minY;
    RING_BBOX[p * 4 + 2] = maxX;
    RING_BBOX[p * 4 + 3] = maxY;
  }
})();

function pointInPolygon(lon, lat, ring) {
  let inside = false;
  const n = ring.length;
  for (let i = 0, j = n - 2; i < n - 1; j = i, i += 2) {
    const xi = ring[i], yi = ring[i + 1];
    const xj = ring[j], yj = ring[j + 1];
    if (((yi > lat) !== (yj > lat)) && (lon < (xj - xi) * (lat - yi) / (yj - yi) + xi))
      inside = !inside;
  }
  return inside;
}

function isLand(lon, lat) {
  for (let p = 0; p < LAND_POLYGONS.length; p++) {
    const b = p * 4;
    if (lon < RING_BBOX[b] || lon > RING_BBOX[b + 2] ||
        lat < RING_BBOX[b + 1] || lat > RING_BBOX[b + 3]) continue;
    if (pointInPolygon(lon, lat, LAND_POLYGONS[p])) return true;
  }
  return false;
}

// ---------------------------------------------------------------------------
// Canvas texture for particle shapes
// ---------------------------------------------------------------------------
function makeShapeTexture(shape) {
  const size = 64;
  const cv = document.createElement('canvas');
  cv.width = cv.height = size;
  const ctx = cv.getContext('2d');
  const c = size / 2, r = size / 2 - 2;
  ctx.fillStyle = '#ffffff';
  if (shape === 'circle') {
    ctx.beginPath();
    ctx.arc(c, c, r, 0, Math.PI * 2);
    ctx.fill();
  } else if (shape === 'square') {
    ctx.fillRect(c - r, c - r, r * 2, r * 2);
  } else {
    ctx.beginPath();
    ctx.moveTo(c, c - r);
    ctx.lineTo(c + r, c + r);
    ctx.lineTo(c - r, c + r);
    ctx.closePath();
    ctx.fill();
  }
  return new THREE.CanvasTexture(cv);
}

// ---------------------------------------------------------------------------
// Color lookup: [grayStart, grayEnd, alphaStart, alphaEnd]
// Indexed by dark(0) / light(2) + land(+1). Light-mode land targets #252525.
// ---------------------------------------------------------------------------
const COLOR_TABLE = [
  [0.102, 0.353, 0.15, 0.60], // dark ocean
  [0.168, 0.659, 0.50, 1.00], // dark land
  [0.725, 0.420, 0.20, 0.70], // light ocean  (lighter shade)
  [0.553, 0.145, 0.55, 1.00], // light land   (continents trending #252525 = 0.145)
];

function particleColor(t, dark, land) {
  const row = COLOR_TABLE[(dark ? 0 : 2) + (land ? 1 : 0)];
  return [row[0] + t * (row[1] - row[0]), row[2] + t * (row[3] - row[2])];
}

