const canvas = document.getElementById('globe-canvas');
const renderer = new THREE.WebGLRenderer({ canvas, antialias: true, alpha: false });
renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
const _initW = canvas.clientWidth || window.innerWidth;
const _initH = canvas.clientHeight || window.innerHeight;
renderer.setSize(_initW, _initH, false);

const scene = new THREE.Scene();
const camera = new THREE.PerspectiveCamera(45, _initW / _initH, 0.1, 100);
camera.position.z = 12;

const rotGroup = new THREE.Group();
scene.add(rotGroup);

// Compute margin matching CSS --margin breakpoints
function getPageMargin(w) {
  if (w <= 768)  return 18;
  if (w <= 1024) return 48;
  if (w <= 1280) return 80;
  if (w <= 1440) return 140;
  return 220;
}

// Desktop default radius
const DESKTOP_DEFAULT_RADIUS = 2.6;

function updateGlobeOffset() {
  const w = canvas.clientWidth || window.innerWidth;
  const h = canvas.clientHeight || window.innerHeight;
  const halfH = camera.position.z * Math.tan((camera.fov / 2) * Math.PI / 180);
  const halfW = halfH * (w / h);
  const worldPerPx = (halfW * 2) / w;

  if (w <= 768) {
    const margin = getPageMargin(w); // 18px on mobile
    // Globe diameter = viewport width minus both page margins
    const availableWidth = w - margin * 2;
    const mobileR = (availableWidth / 2) * worldPerPx;
    if (Math.abs(state.globeRadius - mobileR) > 0.03) {
      state.globeRadius = mobileR;
      scheduleRebuild();
    }
    // X: center of available area = center of viewport (margins are symmetric)
    rotGroup.position.x = 0;
    // Y: vertically center on the mobile-globe-slot
    const slot = document.querySelector('.mobile-globe-slot');
    if (slot) {
      const r = slot.getBoundingClientRect();
      const slotCenterPx = r.top + r.height / 2;
      rotGroup.position.y = (h / 2 - slotCenterPx) * worldPerPx;
    } else {
      rotGroup.position.y = 0;
    }
  } else {
    // Desktop/tablet: restore default radius if coming back from mobile
    if (Math.abs(state.globeRadius - DESKTOP_DEFAULT_RADIUS) > 0.03) {
      state.globeRadius = DESKTOP_DEFAULT_RADIUS;
      // Update the slider UI value
      const radiusEl = document.getElementById('radius');
      const radiusVal = document.getElementById('radius-val');
      if (radiusEl) radiusEl.value = DESKTOP_DEFAULT_RADIUS;
      if (radiusVal) radiusVal.textContent = DESKTOP_DEFAULT_RADIUS.toFixed(1);
      scheduleRebuild();
    }
    const margin = getPageMargin(w);
    const gap = w <= 1024 ? 40 : 80;
    const rightColLeft  = w / 2 + gap / 2;
    const rightColRight = w - margin;
    const rightColCenterPx = (rightColLeft + rightColRight) / 2;
    rotGroup.position.x = (rightColCenterPx - w / 2) * worldPerPx;
    rotGroup.position.y = 0;
  }
}
updateGlobeOffset();

let geometry = null;
let points = null;
let material = null;
let shapeTexture = makeShapeTexture('circle');

const _worldPos = new THREE.Vector3();
const _matWorld = new THREE.Matrix4();
const _localHit = new THREE.Vector3();
const _invMat = new THREE.Matrix4();
const _dir = new THREE.Vector3();
const _scratchRaycaster = new THREE.Raycaster();
const _scratchNdc = new THREE.Vector2();

// ---------------------------------------------------------------------------
// Build / rebuild particle system
// ---------------------------------------------------------------------------
function buildGlobe() {
  if (points) {
    rotGroup.remove(points);
    geometry.dispose();
    material.dispose();
  }

  const count = state.particleCount;
  particleCount = count;
  basePositions = new Float32Array(count * 3);
  isLandArr = new Uint8Array(count);
  offsets = new Float32Array(count * 3);
  rippleVels = new Float32Array(count * 3);
  rippleTimers = new Float32Array(count);
  hoverTargetOffsets = new Float32Array(count * 3);
  hoverDirty.clear();
  activeRippleCount = 0;

  const R = state.globeRadius;
  const phi = Math.PI * (3 - Math.sqrt(5));

  for (let i = 0; i < count; i++) {
    const y = 1 - (i / (count - 1)) * 2;
    const r = Math.sqrt(Math.max(0, 1 - y * y));
    const theta = phi * i;
    const x = Math.cos(theta) * r;
    const z = Math.sin(theta) * r;
    basePositions[i * 3]     = x * R;
    basePositions[i * 3 + 1] = y * R;
    basePositions[i * 3 + 2] = z * R;
    const lat = Math.asin(y) * (180 / Math.PI);
    const lon = Math.atan2(-z, x) * (180 / Math.PI);
    isLandArr[i] = isLand(lon, lat) ? 1 : 0;
  }

  geometry = new THREE.BufferGeometry();
  geometry.setAttribute('position', new THREE.BufferAttribute(basePositions.slice(), 3));
  geometry.setAttribute('color', new THREE.BufferAttribute(new Float32Array(count * 4), 4));

  material = new THREE.PointsMaterial({
    vertexColors: true,
    transparent: true,
    sizeAttenuation: true,
    depthWrite: false,
    size: state.particleSize * 10,
    map: shapeTexture,
    alphaTest: 0.05,
  });

  points = new THREE.Points(geometry, material);
  rotGroup.add(points);
}

// ---------------------------------------------------------------------------
// Color update (per frame, depth-based)
// ---------------------------------------------------------------------------
function updateColors() {
  const dark = state.isDark;
  const colors = geometry.attributes.color.array;
  rotGroup.updateMatrixWorld(true);
  _matWorld.copy(rotGroup.matrixWorld);

  const m = _matWorld.elements;
  const R = state.globeRadius;

  for (let i = 0; i < particleCount; i++) {
    const ix = i * 3;
    const px = basePositions[ix]     + offsets[ix];
    const py = basePositions[ix + 1] + offsets[ix + 1];
    const pz = basePositions[ix + 2] + offsets[ix + 2];

    // Inlined world-space Z (avoids Vector3 allocation overhead)
    const wz = m[2] * px + m[6] * py + m[10] * pz + m[14];

    const t = wz > R ? 1 : wz < -R ? 0 : (wz / R + 1) * 0.5;
    const land = isLandArr[i] === 1;
    const row = COLOR_TABLE[(dark ? 0 : 2) + (land ? 1 : 0)];
    let gray = row[0] + t * (row[1] - row[0]);
    let alpha = row[2] + t * (row[3] - row[2]);
    // Orange land mode: land particles render as #ff4c02 (sRGB).
    // Three.js writes raw colors in linear space — convert sRGB → linear so the
    // rendered pixel actually reads as #ff4c02 on screen. Depth is applied via
    // alpha only so the hue stays exact regardless of rotation.
    // sRGB(#ff4c02) = (1.0, 0.2980, 0.00784) → linear = (1.0, 0.0722, 0.000607)
    let isOrange = false;
    if (state.orangeLand && land) {
      isOrange = true;
      alpha = 0.55 + t * 0.45;  // depth → alpha only (keeps hue intact)
    }

    const hw = hoveredParticles.get(i);
    if (hw !== undefined) {
      if (dark) {
        gray  = gray + (1.0 - gray) * (0.92 * hw);
        alpha = Math.min(1.0, alpha + 0.65 * hw);
      } else {
        gray  = Math.max(0.0, gray - 0.75 * hw);
        alpha = Math.min(1.0, alpha + 0.65 * hw);
      }
    }

    // Light-wave: coin-drop concentric rings, color-only (no position change)
    if (lightWaves.length > 0) {
      const bx = basePositions[ix];
      const by = basePositions[ix + 1];
      const bz = basePositions[ix + 2];
      for (let w = 0; w < lightWaves.length; w++) {
        const lw = lightWaves[w];
        // This ring hasn't started yet
        const effectiveAge = lw.age - lw.ringDelay;
        if (effectiveAge <= 0) continue;

        const activeLife = lw.maxAge - lw.ringDelay;
        const progress = Math.min(effectiveAge / activeLife, 1.0);

        // Ease-out: ring starts fast, slows as it approaches antipodal point (like water)
        const eased = 1 - Math.pow(1 - progress, 2);
        // Expand from 0 → 2R (exact chord distance to antipodal point)
        const ringRadius = eased * 2.0 * R;
        // Tight ring width so the 3 rings read as distinct bands; widens slightly as it travels
        const ringWidth = R * (0.12 + progress * 0.10);

        const dx = bx - lw.x, dy = by - lw.y, dz = bz - lw.z;
        const dist = Math.sqrt(dx*dx + dy*dy + dz*dz);
        const delta = dist - ringRadius;

        // Gaussian ring — crisp crest, soft falloff on both sides
        const ringW = Math.exp(-(delta * delta) / (2 * ringWidth * ringWidth));
        // Envelope: quick fade-in, then gentle decay as ring reaches antipode
        const envelope = Math.pow(1 - progress, 0.5) * Math.min(progress * 8, 1.0);
        const brightness = lw.amplitude * ringW * envelope;

        if (brightness > 0.004) {
          if (dark) {
            gray  = gray + (1.0 - gray) * brightness;
            alpha = Math.min(1.0, alpha + 0.45 * brightness);
          } else {
            gray  = Math.max(0.0, gray - 0.55 * brightness);
            alpha = Math.min(1.0, alpha + 0.45 * brightness);
          }
        }
      }
    }

    const ic = i * 4;
    if (isOrange) {
      // Linearised sRGB of #ff4c02
      colors[ic]     = 1.0;
      colors[ic + 1] = 0.0722;
      colors[ic + 2] = 0.000607;
    } else {
      colors[ic] = colors[ic + 1] = colors[ic + 2] = gray;
    }
    colors[ic + 3] = alpha;
  }
  geometry.attributes.color.needsUpdate = true;
}

// ---------------------------------------------------------------------------
// Click light-wave — purely a color effect, no position change.
// A ring of brightness expands outward from the click point across the globe
// surface over ~300ms, with a soft Gaussian profile on both leading and
// trailing edges and a gentle fade-out over the wave's lifetime.
// ---------------------------------------------------------------------------
const lightWaves = [];  // active waves: { x,y,z (local), age, maxAge }
let globeClickPulse = 0; // 0..1, decays after click — used by grid to boost dots

function spawnLightWave(ndcX, ndcY) {
  _scratchNdc.set(ndcX, ndcY);
  _scratchRaycaster.setFromCamera(_scratchNdc, camera);

  const dir = _scratchRaycaster.ray.direction;
  const R = state.globeRadius;

  const ox = _scratchRaycaster.ray.origin.x - rotGroup.position.x;
  const oy = _scratchRaycaster.ray.origin.y - rotGroup.position.y;
  const oz = _scratchRaycaster.ray.origin.z - rotGroup.position.z;
  const a = dir.dot(dir);
  const b = 2 * (ox * dir.x + oy * dir.y + oz * dir.z);
  const c = ox * ox + oy * oy + oz * oz - R * R;
  const disc = b * b - 4 * a * c;
  if (disc < 0) return;
  const t = (-b - Math.sqrt(disc)) / (2 * a);
  if (t < 0) return;

  rotGroup.updateMatrixWorld(true);
  _localHit.copy(_scratchRaycaster.ray.origin).addScaledVector(dir, t);
  _invMat.copy(rotGroup.matrixWorld).invert();
  _localHit.applyMatrix4(_invMat);

  // 3 distinct light rings expanding from click to antipodal point.
  // Staggered delays so they read as 3 separate waves, not one blurry blob.
  const base = { x: _localHit.x, y: _localHit.y, z: _localHit.z };
  lightWaves.push({ ...base, age: 0, maxAge: 1.6, ringDelay: 0.0,  amplitude: 0.85 });
  lightWaves.push({ ...base, age: 0, maxAge: 1.6, ringDelay: 0.22, amplitude: 0.60 });
  lightWaves.push({ ...base, age: 0, maxAge: 1.6, ringDelay: 0.44, amplitude: 0.38 });
}

// ---------------------------------------------------------------------------
// Smoothly ease current offsets toward hoverTargetOffsets (per-frame).
// Hover lifts a soft disk of particles outward; releasing the hover eases
// them back. Shares the `offsets` buffer with the ripple sim, so hover
// displacement also appears in updateColors().
// ---------------------------------------------------------------------------
// hoverDirty tracks indices whose hover offset or target is nonzero — lets us
// skip the full O(N) scan once all hovered particles have fully eased back.
const hoverDirty = new Set();

function updateHoverDisplacement(dt) {
  if (!hoverTargetOffsets || hoverDirty.size === 0) return false;
  const k = 1 - Math.exp(-dt * 5); // slower ease = smoother, more fluid cursor tracking
  let anyChange = false;

  for (const i of hoverDirty) {
    const ix = i * 3;
    const tx = hoverTargetOffsets[ix];
    const ty = hoverTargetOffsets[ix + 1];
    const tz = hoverTargetOffsets[ix + 2];
    const cx = offsets[ix], cy = offsets[ix + 1], cz = offsets[ix + 2];
    const nx = cx + (tx - cx) * k;
    const ny = cy + (ty - cy) * k;
    const nz = cz + (tz - cz) * k;
    if (nx !== cx || ny !== cy || nz !== cz) {
      offsets[ix]     = nx;
      offsets[ix + 1] = ny;
      offsets[ix + 2] = nz;
      anyChange = true;
    }
    // Remove from dirty set once both target and offset are effectively zero
    if (tx === 0 && ty === 0 && tz === 0 &&
        Math.abs(nx) < 1e-5 && Math.abs(ny) < 1e-5 && Math.abs(nz) < 1e-5) {
      offsets[ix] = offsets[ix + 1] = offsets[ix + 2] = 0;
      hoverDirty.delete(i);
    }
  }
  return anyChange;
}

function commitPositions() {
  const positions = geometry.attributes.position.array;
  for (let i = 0; i < particleCount; i++) {
    const ix = i * 3;
    positions[ix]     = basePositions[ix]     + offsets[ix];
    positions[ix + 1] = basePositions[ix + 1] + offsets[ix + 1];
    positions[ix + 2] = basePositions[ix + 2] + offsets[ix + 2];
  }
  geometry.attributes.position.needsUpdate = true;
}

// ---------------------------------------------------------------------------
// Animation loop
// ---------------------------------------------------------------------------
let prevTime = performance.now();

function animate() {
  requestAnimationFrame(animate);
  const now = performance.now();
  const dt = Math.min((now - prevTime) / 1000, 0.05);
  prevTime = now;

  rotGroup.rotation.y += 0.0003 * state.autoSpeed;

  if (!isDragging) {
    rotGroup.rotation.y += velX;
    velX *= state.damping;
    if (Math.abs(velX) < 0.00001) velX = 0;
  }

  // Advance light waves
  for (let i = lightWaves.length - 1; i >= 0; i--) {
    lightWaves[i].age += dt;
    if (lightWaves[i].age >= lightWaves[i].maxAge) lightWaves.splice(i, 1);
  }
  // Decay grid click pulse
  if (globeClickPulse > 0) globeClickPulse = Math.max(0, globeClickPulse - dt * 2.5);

  const hoverChanged = updateHoverDisplacement(dt);
  if (hoverChanged) commitPositions();

  updateColors();
  renderer.render(scene, camera);
}

// ---------------------------------------------------------------------------
// Input
// ---------------------------------------------------------------------------
function getPointerPos(e) {
  return { x: e.clientX, y: e.clientY };
}

function clearHoverTarget() {
  if (!hoverTargetOffsets) return;
  // Reset targets only; hoverDirty keeps particles in the ease-back loop until
  // their offsets reach zero, then they self-remove from the set.
  hoverTargetOffsets.fill(0);
}

function updateHoveredParticles(ndcX, ndcY) {
  clearHoverTarget();
  if (isDragging) {
    hoveredParticles.clear();
    return;
  }

  _scratchNdc.set(ndcX, ndcY);
  _scratchRaycaster.setFromCamera(_scratchNdc, camera);

  const dir = _scratchRaycaster.ray.direction;
  const R = state.globeRadius;

  // Sphere-center-relative origin: the globe is translated to rotGroup.position,
  // so we solve the intersection against a sphere at origin by offsetting the ray.
  const ox = _scratchRaycaster.ray.origin.x - rotGroup.position.x;
  const oy = _scratchRaycaster.ray.origin.y - rotGroup.position.y;
  const oz = _scratchRaycaster.ray.origin.z - rotGroup.position.z;
  const a = dir.dot(dir);
  const b = 2 * (ox * dir.x + oy * dir.y + oz * dir.z);
  const c = ox * ox + oy * oy + oz * oz - R * R;
  const disc = b * b - 4 * a * c;
  if (disc < 0) { hoveredParticles.clear(); return; }
  const t = (-b - Math.sqrt(disc)) / (2 * a);
  if (t < 0) { hoveredParticles.clear(); return; }

  rotGroup.updateMatrixWorld(true);
  _localHit.copy(_scratchRaycaster.ray.origin).addScaledVector(dir, t);
  _invMat.copy(rotGroup.matrixWorld).invert();
  _localHit.applyMatrix4(_invMat);

  hoveredParticles.clear();
  // Use a slightly wider search radius so smoothstep has room to taper to zero
  const searchRange = HOVER_RANGE * 1.15;
  const searchRangeSq = searchRange * searchRange;
  const lift = R * HOVER_LIFT;

  // lightSigma for brightness spotlight; dispSigma for displacement zone
  const lightSigma = HOVER_RANGE / 3.0;
  const dispSigma  = HOVER_RANGE / 2.4;
  const invTwoLightSq = 1 / (2 * lightSigma * lightSigma);
  const invTwoDispSq  = 1 / (2 * dispSigma  * dispSigma);

  // smoothstep(edge0, edge1, x): returns 0 at x<=edge0, 1 at x>=edge1, smooth curve between
  // We use it to fade both light and displacement to exactly 0 at HOVER_RANGE
  const smoothstep = (e0, e1, x) => {
    const t = Math.max(0, Math.min(1, (x - e0) / (e1 - e0)));
    return t * t * (3 - 2 * t);
  };

  for (let i = 0; i < particleCount; i++) {
    const ix = i * 3;
    const bx = basePositions[ix];
    const by = basePositions[ix + 1];
    const bz = basePositions[ix + 2];
    const dx = bx - _localHit.x;
    const dy = by - _localHit.y;
    const dz = bz - _localHit.z;
    const distSq = dx * dx + dy * dy + dz * dz;
    if (distSq >= searchRangeSq) continue;

    const d = Math.sqrt(distSq);
    // Edge fade: smoothstep from 1 at d=0 down to 0 at d=HOVER_RANGE (starts fading at 60%)
    const edgeFade = 1 - smoothstep(HOVER_RANGE * 0.6, HOVER_RANGE, d);

    // Light weight: Gaussian spotlight * edge fade so it reaches exactly 0 at boundary
    const lightW = Math.exp(-distSq * invTwoLightSq) * edgeFade;
    hoveredParticles.set(i, lightW);

    const blen = Math.sqrt(bx * bx + by * by + bz * bz);
    if (blen < 0.0001) continue;
    const invBlen = 1 / blen;
    const surfNx = bx * invBlen;
    const surfNy = by * invBlen;
    const surfNz = bz * invBlen;

    // Displacement weight: Gaussian * edgeFade — zero at boundary, no hard cutoff
    const dispW = Math.exp(-distSq * invTwoDispSq) * edgeFade;

    // Direction: push each particle AWAY from the cursor on the sphere surface.
    // Take the vector from hit point to particle, project onto sphere tangent plane,
    // normalize it — that's the "flee" direction. Particles closest to cursor flee most.
    let fleeX = 0, fleeY = 0, fleeZ = 0;
    if (d > 0.001) {
      const invD = 1 / d;
      const ux = dx * invD, uy = dy * invD, uz = dz * invD;
      // Project onto tangent plane at this particle's surface normal
      const dot = ux * surfNx + uy * surfNy + uz * surfNz;
      fleeX = ux - surfNx * dot;
      fleeY = uy - surfNy * dot;
      fleeZ = uz - surfNz * dot;
      const flen = Math.sqrt(fleeX*fleeX + fleeY*fleeY + fleeZ*fleeZ);
      if (flen > 0.001) { const inv = 1/flen; fleeX*=inv; fleeY*=inv; fleeZ*=inv; }
    }

    // 45% flee (creates the gap), 55% radial lift (dome feel). Less flee = smaller gap.
    const magnitude = lift * dispW;
    hoverTargetOffsets[ix]     = (fleeX * 0.45 + surfNx * 0.55) * magnitude;
    hoverTargetOffsets[ix + 1] = (fleeY * 0.45 + surfNy * 0.55) * magnitude;
    hoverTargetOffsets[ix + 2] = (fleeZ * 0.45 + surfNz * 0.55) * magnitude;
    hoverDirty.add(i);
  }
}

// Unified interaction element: desktop uses canvas, mobile uses the slot
const mobileSlot = document.querySelector('.mobile-globe-slot');
const interactiveTargets = mobileSlot ? [canvas, mobileSlot] : [canvas];

function attachPointerDown(target) {
  target.addEventListener('pointerdown', (e) => {
    isDragging = true;
    try { target.setPointerCapture(e.pointerId); } catch (_) {}
    dragLast = getPointerPos(e);
    prevMoveTime = performance.now();
    dragDist = 0;
    velX = 0;
    smoothVelX = 0;
    hoveredParticles.clear();
    clearHoverTarget();
    e.preventDefault();
  });
}
interactiveTargets.forEach(attachPointerDown);

function onPointerMove(e) {
  const pos = getPointerPos(e);
  // NDC always computed relative to the globe canvas (since that's where the scene lives)
  const rect = canvas.getBoundingClientRect();
  const ndcX = ((pos.x - rect.left) / rect.width) * 2 - 1;
  const ndcY = -((pos.y - rect.top) / rect.height) * 2 + 1;

  if (isDragging) {
    const dx = pos.x - dragLast.x;
    const now = performance.now();
    const elapsed = Math.max(4, now - prevMoveTime);
    rotGroup.rotation.y += dx * 0.01;
    const instVel = (dx / elapsed) * 16;
    smoothVelX = smoothVelX * 0.6 + instVel * 0.4;
    dragDist += Math.abs(dx);
    dragLast = pos;
    prevMoveTime = now;
  } else {
    updateHoveredParticles(ndcX, ndcY);
  }
}
interactiveTargets.forEach(t => t.addEventListener('pointermove', onPointerMove));

function onPointerUp(e) {
  if (!isDragging) return;
  isDragging = false;

  if (dragDist < 5) {
    const rect = canvas.getBoundingClientRect();
    const pos = getPointerPos(e);
    spawnLightWave(
      ((pos.x - rect.left) / rect.width) * 2 - 1,
      -((pos.y - rect.top) / rect.height) * 2 + 1
    );
    globeClickPulse = 1.0;
    // Haptic: pattern mimics the 3 ripples — vibrate, pause, vibrate, pause, vibrate
    // Each pulse corresponds to one light ring (amplitudes 0.85, 0.60, 0.38 → durations)
    if (navigator.vibrate) navigator.vibrate([22, 180, 16, 200, 12]);
    velX = 0;
    smoothVelX = 0;
  } else {
    velX = Math.max(-0.06, Math.min(0.06, smoothVelX));
  }
}
interactiveTargets.forEach(t => t.addEventListener('pointerup', onPointerUp));
interactiveTargets.forEach(t => t.addEventListener('pointercancel', onPointerUp));

canvas.addEventListener('pointerleave', () => {
  hoveredParticles.clear();
  clearHoverTarget();
});

function onResize() {
  const w = canvas.clientWidth || window.innerWidth;
  const h = canvas.clientHeight || window.innerHeight;
  renderer.setSize(w, h, false);
  camera.aspect = w / h;
  camera.updateProjectionMatrix();
  // Run twice: once immediately, once after layout settles (mobile slot bounds)
  updateGlobeOffset();
  requestAnimationFrame(updateGlobeOffset);
}
window.addEventListener('resize', onResize);
window.addEventListener('orientationchange', onResize);

// ---------------------------------------------------------------------------
// Controls — sliders are debounced for expensive rebuilds (particle count /
// radius) so dragging the slider doesn't rebuild the globe on every input.
// ---------------------------------------------------------------------------
function setTheme(dark) {
  state.isDark = dark;
  document.body.classList.toggle('dark', dark);
  document.body.classList.toggle('light', !dark);
  renderer.setClearColor(dark ? 0x0B0C10 : 0xF5F2EC, 1);
}

let rebuildTimer = 0;
function scheduleRebuild() {
  if (rebuildTimer) clearTimeout(rebuildTimer);
  rebuildTimer = setTimeout(() => {
    rebuildTimer = 0;
    buildGlobe();
  }, 120);
}

function bindSlider(id, valId, stateProp, transform, rebuild, onUpdate) {
  const el = document.getElementById(id);
  const valEl = document.getElementById(valId);
  el.addEventListener('input', () => {
    state[stateProp] = transform(el.value);
    const decimals = stateProp === 'autoSpeed' || stateProp === 'particleCount' ? 0
      : stateProp === 'particleSize' ? 3
      : 2;
    valEl.textContent = state[stateProp].toFixed(decimals);
    if (rebuild) scheduleRebuild();
    if (onUpdate) onUpdate();
  });
}

document.getElementById('theme-toggle').addEventListener('click', () => setTheme(!state.isDark));

// Map color toggle: orange land particles on/off
(function setupMapColorBtn() {
  const btn = document.getElementById('map-color-btn');
  if (!btn) return;
  btn.addEventListener('click', () => {
    state.orangeLand = !state.orangeLand;
    btn.classList.toggle('active', state.orangeLand);
  });
})();

bindSlider('count',   'count-val',  'particleCount', v => parseInt(v),   true);
bindSlider('radius',  'radius-val', 'globeRadius',   v => parseFloat(v), true);
bindSlider('speed',   'speed-val',  'autoSpeed',     v => parseFloat(v), false);
bindSlider('psize',   'size-val',   'particleSize',  v => parseFloat(v), false, () => { material.size = state.particleSize * 10; });
bindSlider('damping', 'damp-val',   'damping',       v => parseFloat(v), false);

const VALID_SHAPES = new Set(['circle', 'square', 'triangle']);
document.querySelectorAll('.shape-btn').forEach(btn => {
  btn.addEventListener('click', () => {
    const shape = btn.dataset.shape;
    if (!VALID_SHAPES.has(shape)) return;
    document.querySelectorAll('.shape-btn').forEach(b => b.classList.remove('active'));
    btn.classList.add('active');
    state.shape = shape;
    shapeTexture.dispose();
    shapeTexture = makeShapeTexture(state.shape);
    if (material) material.map = shapeTexture;
  });
});

document.getElementById('collapse-btn').addEventListener('click', () => {
  const panel = document.getElementById('controls');
  panel.classList.toggle('collapsed');
});

// ---------------------------------------------------------------------------
// Hero cycling word
// ---------------------------------------------------------------------------
(function cycleHeroWord() {
  const words = ['real estate', 'stock markets', 'governments', 'education', 'music', 'everyone'];
  const el = document.getElementById('cycle-word');
  if (!el) return;

  // Pre-measure the widest word and lock the element to that width
  // so the layout never reflows as words change.
  function lockWidth() {
    el.style.minWidth = '';
    el.style.display = 'inline-block';
    let maxW = 0;
    const orig = el.textContent;
    words.forEach(w => {
      el.textContent = w;
      const bw = el.getBoundingClientRect().width;
      if (bw > maxW) maxW = bw;
    });
    el.textContent = orig;
    el.style.minWidth = maxW + 'px';
  }
  lockWidth();
  window.addEventListener('resize', lockWidth);

  let idx = 0;
  setInterval(() => {
    idx = (idx + 1) % words.length;
    el.classList.add('fading');
    setTimeout(() => {
      el.textContent = words[idx];
      el.classList.remove('fading');
    }, 260);
  }, 2200);
})();

// ---------------------------------------------------------------------------
// Mobile menu
// ---------------------------------------------------------------------------
(function mobileMenu() {
  const btn = document.getElementById('mobile-menu-btn');
  const drawer = document.getElementById('mobile-drawer');
  if (!btn || !drawer) return;
  btn.addEventListener('click', () => {
    const open = drawer.classList.toggle('open');
    drawer.setAttribute('aria-hidden', open ? 'false' : 'true');
  });
  // Close drawer when a link is tapped
  drawer.querySelectorAll('a').forEach(a => {
    a.addEventListener('click', () => {
      drawer.classList.remove('open');
      drawer.setAttribute('aria-hidden', 'true');
    });
  });
})();

// ---------------------------------------------------------------------------
// Init
// ---------------------------------------------------------------------------
setTheme(true);
buildGlobe();
// Ensure globe position is correct after first layout pass (mobile slot bounds settle)
requestAnimationFrame(() => { updateGlobeOffset(); });
animate();

// Expose state for debugging
window.__globeState = state;

// ---------------------------------------------------------------------------
// Background grid — 12 faint vertical lines, each with a glowing dot that
// travels up/down at randomised speed and interval. Reacts to light/dark theme.
// ---------------------------------------------------------------------------
(function backgroundGrid() {
  const gc = document.getElementById('grid-canvas');
  if (!gc) return;
  const ctx = gc.getContext('2d');
  const BASE_DOT_RADIUS = 1.5;

  // Responsive line count
  function getNumLines() {
    const w = window.innerWidth;
    if (w <= 768) return 4;
    if (w <= 1024) return 8;
    return 12;
  }

  // Create enough dot state for maximum lines
  const MAX_LINES = 12;
  const dots = Array.from({ length: MAX_LINES }, () => ({
    y:        Math.random(),
    speed:    (Math.random() * 0.04 + 0.015) * (Math.random() < 0.5 ? 1 : -1),
    active:   false,
    waiting:  true,
    waitUntil: performance.now() + Math.random() * 6000,
  }));

  let w = 0, h = 0;

  function resize() {
    w = window.innerWidth;
    h = window.innerHeight;
    gc.width  = w * window.devicePixelRatio;
    gc.height = h * window.devicePixelRatio;
    gc.style.width  = w + 'px';
    gc.style.height = h + 'px';
    ctx.scale(window.devicePixelRatio, window.devicePixelRatio);
  }
  resize();
  window.addEventListener('resize', () => { ctx.setTransform(1,0,0,1,0,0); resize(); });

  function isDarkMode() { return document.body.classList.contains('dark'); }

  function draw(ts) {
    requestAnimationFrame(draw);
    ctx.clearRect(0, 0, w, h);

    const dark = isDarkMode();
    const lineColor = dark ? 'rgba(255,255,255,0.045)' : 'rgba(0,0,0,0.055)';
    const dotColor  = dark ? [255, 255, 255] : [80, 80, 80];

    const numLines = getNumLines();
    const margin = getPageMargin(w);
    const gridStart = margin;
    const gridEnd   = w - margin;
    const colW = numLines > 1 ? (gridEnd - gridStart) / (numLines - 1) : 0;

    // Pulse from globe click: boosts dot size and glow by 10-15%
    const pulse = typeof globeClickPulse !== 'undefined' ? globeClickPulse : 0;
    const dotScale = 1 + pulse * 0.13;
    const glowAlpha0 = 0.45 + pulse * 0.30;
    const coreAlpha  = 0.60 + pulse * 0.25;

    for (let li = 0; li < numLines; li++) {
      const x = gridStart + colW * li;
      const dot = dots[li];
      const dotR = BASE_DOT_RADIUS * dotScale;

      // Draw vertical line
      ctx.beginPath();
      ctx.moveTo(x, 0);
      ctx.lineTo(x, h);
      ctx.strokeStyle = lineColor;
      ctx.lineWidth = 1;
      ctx.stroke();

      // Dot state machine
      if (dot.waiting) {
        if (ts >= dot.waitUntil) { dot.waiting = false; dot.active = true; }
      }

      if (dot.active) {
        dot.y += dot.speed / 60;
        if (dot.y > 1.05) {
          dot.y = 1.05;
          dot.speed = -(Math.random() * 0.04 + 0.015);
          dot.active = false; dot.waiting = true;
          dot.waitUntil = ts + 2000 + Math.random() * 5000;
        } else if (dot.y < -0.05) {
          dot.y = -0.05;
          dot.speed = (Math.random() * 0.04 + 0.015);
          dot.active = false; dot.waiting = true;
          dot.waitUntil = ts + 2000 + Math.random() * 5000;
        }

        const py = dot.y * h;
        const [r,g,b] = dotColor;
        const grad = ctx.createRadialGradient(x, py, 0, x, py, dotR * 4);
        grad.addColorStop(0,   `rgba(${r},${g},${b},${glowAlpha0.toFixed(2)})`);
        grad.addColorStop(0.4, `rgba(${r},${g},${b},${(glowAlpha0 * 0.33).toFixed(2)})`);
        grad.addColorStop(1,   `rgba(${r},${g},${b},0)`);
        ctx.beginPath();
        ctx.arc(x, py, dotR * 4, 0, Math.PI * 2);
        ctx.fillStyle = grad;
        ctx.fill();

        ctx.beginPath();
        ctx.arc(x, py, dotR, 0, Math.PI * 2);
        ctx.fillStyle = `rgba(${r},${g},${b},${coreAlpha.toFixed(2)})`;
        ctx.fill();
      }
    }
  }

  requestAnimationFrame(draw);
}());
